class Main {
  static void validateAge(int age) {
    if (age < 0) {
      // 1. Manually build the Explosion Object
      // 2. Hurling it instantly!
      throw new IllegalArgumentException("Age cannot be negative!!");
    }
    System.out.println("Age is valid.");
  }

  public static void main(String[] args) {
    // Using the method normally
    validateAge(25);

    // Using the method with bad data. It will explode!
    validateAge(-5);
  }
}
